 42→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 43→
 44→const AppAuthModal = () => {
 45→  const {showAuthModal, closeAuthModal} = useAuth();
 46→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 47→}
 48→
 49→const AppSplash = () => {
 50→  const { loading } = useAuth();
 51→  return <Loader isLoading={loading} />;
 52→}
 53→
 54→const App = () => {
 55→
 56→  const theme = {
 57→    paragraph: 'editor-paragraph',
 58→    heading: {
 59→      h1: 'editor-heading-h1',
 60→      h2: 'editor-heading-h2',
 61→      h3: 'editor-heading-h3',
 62→    },
 63→    quote: 'editor-quote',
 64→    text: {
 65→      bold: 'editor-text-bold',
 66→      italic: 'editor-text-italic',
 67→      underline: 'editor-text-underline',
 68→    }
 69→  }
 70→  
 71→  const initaConfig = {
 72→  namespace: "MyLexicalEditor",
 73→  theme,
 74→  //register nodes
 75→  nodes: [ImageNode, HeadingNode, QuoteNode],
 76→  onError(error){
 77→  throw error;
 78→  },
 79→}
 80→
 81→  return (
 82→    <>
 83→    <LexicalComposer initialConfig={initaConfig}>
 84→      <BrowserRouter>
 85→        <SeoManager />
 86→        <AppSplash />
 87→        <Suspense fallback={null}>
 88→          <AppAuthModal/>
 89→          <Routes>
 90→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 91→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 92→            <Route path='/profile' element={<MyProfile/>}>
 93→              <Route index element={<ProfilePostCards/>} />
 94→              <Route path='media' element={<ProfileMediaSection/>} />
 95→              <Route path='myOpinions' element={<MyOpinions/>}/>
 96→              <Route path='stories' element={<ProfileStoriesSection/>}/>
 97→            </Route>
 98→
 99→            <Route path='/visitProfile' element={<Visitprofile/>}>
100→              <Route index element={<VisitedProfilePostCards/>}/>
101→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
102→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
103→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
104→            </Route>
105→
106→            <Route path='/u/:username' element={<Visitprofile/>}>
107→              <Route index element={<VisitedProfilePostCards/>}/>
108→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
109→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
110→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
111→            </Route>
112→
113→            <Route path='/home' element={<HomePage/>}>
114→              <Route index element={<PostCards/>}/>
115→              <Route path='following' element={<PostCards/>}/>
116→              <Route path='explore' element={<ExplorePage/>}/>
117→              <Route path='contentViewer' element={<ContentView/>}/>
118→              <Route path='post/:journalId' element={<ContentView/>}/>
119→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
120→              <Route path='bookmark' element={<Bookmarks/>}/>
121→              <Route path='opinions'element={<OpinionsPage/>}/>
122→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
123→
124→              <Route path='settings' element={<SettingsPage/>}/>
125→
126→              {/* Stories routes */}
127→              <Route path='stories' element={<StoryBrowser/>}/>
128→              <Route path='stories/library' element={<StoryLibrary/>}/>
129→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
130→              <Route path='stories/new' element={<StoryEditor/>}/>
131→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
132→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
133→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
134→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
135→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
136→
137→              {/* route for nested notifications */}
138→              <Route path='notifications' element={<Notifications/>}>
139→                <Route index element={<NotificationCards/>}/>
140→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
141→              </Route>  
142→            </Route>   
143→
144→            <Route path='/login' element={<LoginPage/>}/>
145→            <Route path='/signUp' element={<SignUp/>}/>
146→          </Routes>
147→        </Suspense>
148→      </BrowserRouter>
149→    </LexicalComposer>
150→    </>
151→  )
152→}
153→
154→export default App
