181→        const file = e.target.files[0];
182→        if(file){
183→            setImageFile(file)
184→            const reader = new FileReader();
185→            reader.onloadend = () =>{
186→                setProfilePreview(reader.result)
187→            }
188→            reader.readAsDataURL(file)
189→        }
