192→    const slugifyForUsername = (val) =>
193→        String(val || '').toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
194→
195→    const handleNameChangeForSetup = (e) => {
196→        const newName = e.target.value;
197→        setName(newName);
198→        // Auto-suggest username from name if user hasn't manually edited username
199→        if (!setupUsername || setupUsername === slugifyForUsername(name)) {
200→            const suggested = slugifyForUsername(newName);
201→            setSetupUsername(suggested);
202→            checkUsernameDebounced(suggested);
203→        }
204→    };
205→
206→    const handleUsernameChange = (e) => {
207→        const raw = e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '');
208→        setSetupUsername(raw);
209→        checkUsernameDebounced(raw);
210→    };
211→
212→    const checkUsernameDebounced = (uname) => {
213→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
214→        if (!uname || uname.length < 3) {
215→            setUsernameAvailable(null);
216→            return;
217→        }
218→        setUsernameChecking(true);
219→        usernameCheckTimer.current = setTimeout(async () => {
220→            try {
221→                const result = await checkUsernameAvailability(uname);
222→                setUsernameAvailable(result.available);
223→            } catch {
224→                setUsernameAvailable(null);
225→            } finally {
226→                setUsernameChecking(false);
227→            }
228→        }, 400);
